import numpy as np
from itertools import permutations

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_total_time = float('inf')

    for i, customer in enumerate(unvisited_customers):
        if current_time + np.linalg.norm(cur_truck_pos - customer) / truck_speed > time_windows[i][1]:
            continue

        for perm in permutations([cur_truck_pos] + all_truck_pos + [depot_pos]):
            total_time = current_time
            cur_pos = cur_truck_pos

            for pos in perm:
                total_time += np.linalg.norm(cur_pos - pos) / truck_speed
                cur_pos = pos

                if np.array_equal(pos, customer):
                    total_time = max(total_time, time_windows[i][0])

            total_time += np.linalg.norm(cur_pos - depot_pos) / truck_speed

            if total_time < min_total_time:
                min_total_time = total_time
                best_node = i

    return best_node
